"""
Parameterized generator for GH1078_ultralytics_23546.

Source PR:    https://github.com/ultralytics/ultralytics/pull/23546
Source Issue: N/A

Seed varies: renames 'autobatch' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH1078_ultralytics_23546'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH1078_ultralytics_23546'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('autobatch', 'autobatch' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH1078_ultralytics_23546',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'ultralytics/ultralytics',
                "pr_number": 23546,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/ultralytics/ultralytics/pull/23546",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'tests/test_cuda.py': '# Ultralytics 🚀 AGPL-3.0 License - https://ultralytics.com/license\n\nimport os\nfrom itertools import product\nfrom pathlib import Path\n\nimport pytest\nimport torch\n\nfrom tests import CUDA_DEVICE_COUNT, CUDA_IS_AVAILABLE, MODEL, SOURCE\nfrom ultralytics import YOLO\nfrom ultralytics.cfg import TASK2DATA, TASK2MODEL, TASKS\nfrom ultralytics.utils import ASSETS, IS_JETSON, WEIGHTS_DIR\nfrom ultralytics.utils.autodevice import GPUInfo\nfrom ultralytics.utils.checks import check_amp, check_tensorrt\nfrom ultralytics.utils.torch_utils import TORCH_1_13\n\n# Try to find idle devices if CUDA is available\nDEVICES = []\nif CUDA_IS_AVAILABLE:\n    if IS_JETSON:\n        DEVICES = [0]  # NVIDIA Jetson only has one GPU and does not fully support pynvml library\n    else:\n        gpu_info = GPUInfo()\n        gpu_info.print_status()\n        autodevice_fraction = __import__("os").environ.get("YOLO_AUTODEVICE_FRACTION_FREE", 0.3)\n        if idle_gpus := gpu_info.select_idle_gpu(\n            count=2,\n            min_memory_fraction=autodevice_fraction,\n            min_util_fraction=autodevice_fraction,\n        ):\n            DEVICES = idle_gpus\n\n\ndef test_checks():\n    """Validate CUDA settings against torch CUDA functions."""\n    assert torch.cuda.is_available() == CUDA_IS_AVAILABLE\n    assert torch.cuda.device_count() == CUDA_DEVICE_COUNT\n\n\n@pytest.mark.skipif(not DEVICES, reason="No CUDA devices available")\ndef test_amp():\n    """Test AMP training checks."""\n    model = YOLO("yolo26n.pt").model.to(f"cuda:{DEVICES[0]}")\n    assert check_amp(model)\n\n\n@pytest.mark.slow\n@pytest.mark.skipif(not DEVICES, reason="No CUDA devices available")\n@pytest.mark.parametrize(\n    "task, dynamic, int8, half, batch, simplify, nms",\n    [  # generate all combinations except for exclusion cases\n        (task, dynamic, int8, half, batch, simplify, nms)\n        for task, dynamic, int8, half, batch, simplify, nms in product(\n            TASKS, [True, False], [False], [False], [1, 2], [True, False], [True, False]\n        )\n        if not (\n            (int8 and half) or (task == "classify" and nms) or (task == "obb" and nms and (not TORCH_1_13 or IS_JETSON))\n        )\n    ],\n)\ndef test_export_onnx_matrix(task, dynamic, int8, half, batch, simplify, nms):\n    """Test YOLO exports to ONNX format with various configurations and parameters."""\n    file = YOLO(TASK2MODEL[task]).export(\n        format="onnx",\n        imgsz=32,\n        dynamic=dynamic,\n        int8=int8,\n        half=half,\n        batch=batch,\n        simplify=simplify,\n        nms=nms,\n        device=DEVICES[0],\n        # opset=20 if nms else None,  # fix ONNX Runtime errors with NMS\n    )\n    YOLO(file)([SOURCE] * batch, imgsz=64 if dynamic else 32, device=DEVICES[0])  # exported model inference\n    Path(file).unlink()  # cleanup\n\n\n@pytest.mark.slow\n@pytest.mark.skipif(not DEVICES, reason="No CUDA devices available")\n@pytest.mark.parametrize(\n    "task, dynamic, int8, half, batch",\n    [  # generate all combinations but exclude those where both int8 and half are True\n        (task, dynamic, int8, half, batch)\n        # Note: tests reduced below pending compute availability expansion as GPU CI runner utilization is high\n        # for task, dynamic, int8, half, batch in product(TASKS, [True, False], [True, False], [True, False], [1, 2])\n        for task, dynamic, int8, half, batch in product(TASKS, [True], [True], [False], [2])\n        if not (int8 and half)  # exclude cases where both int8 and half are True\n    ],\n)\ndef test_export_engine_matrix(task, dynamic, int8, half, batch):\n    """Test YOLO model export to TensorRT format for various configurations and run inference."""\n    check_tensorrt()\n    import tensorrt as trt\n\n    is_trt10 = int(trt.__version__.split(".", 1)[0]) >= 10\n    if is_trt10 and int8 and dynamic:\n        pytest.skip("YOLO26 INT8+dynamic export requires explicit quantization on TensorRT 10+")\n\n    file = YOLO(TASK2MODEL[task]).export(\n        format="engine",\n        imgsz=32,\n        dynamic=dynamic,\n        int8=int8,\n        half=half,\n        batch=batch,\n        data=TASK2DATA[task],\n        workspace=1,  # reduce workspace GB for less resource utilization during testing\n        simplify=True,\n        device=DEVICES[0],\n    )\n    YOLO(file)([SOURCE] * batch, imgsz=64 if dynamic else 32, device=DEVICES[0])  # exported model inference\n    Path(file).unlink()  # cleanup\n    Path(file).with_suffix(".cache").unlink(missing_ok=True) if int8 else None  # cleanup INT8 cache\n\n\n@pytest.mark.skipif(not DEVICES, reason="No CUDA devices available")\ndef test_train():\n    """Test model training on a minimal dataset using available CUDA devices."""\n    device = tuple(DEVICES) if len(DEVICES) > 1 else DEVICES[0]\n    # NVIDIA Jetson only has one GPU and therefore skipping checks\n    if not IS_JETSON:\n        results = YOLO(MODEL).train(data="coco8.yaml", imgsz=64, epochs=1, device=device, batch=15, compile=True)\n        results = YOLO(MODEL).train(data="coco128.yaml", imgsz=64, epochs=1, device=device, batch=15, val=False)\n        visible = eval(os.environ["CUDA_VISIBLE_DEVICES"])\n        assert visible == device, f"Passed GPUs \'{device}\', but used GPUs \'{visible}\'"\n        # Note DDP training returns None, single-GPU returns metrics\n        assert (results is None) if len(DEVICES) > 1 else (results is not None)\n\n\n@pytest.mark.slow\n@pytest.mark.skipif(not DEVICES, reason="No CUDA devices available")\ndef test_predict_multiple_devices():\n    """Validate model prediction consistency across CPU and CUDA devices."""\n    model = YOLO("yolo26n.pt")\n\n    # Test CPU\n    model = model.cpu()\n    assert str(model.device) == "cpu"\n    _ = model(SOURCE)\n    assert str(model.device) == "cpu"\n\n    # Test CUDA\n    cuda_device = f"cuda:{DEVICES[0]}"\n    model = model.to(cuda_device)\n    assert str(model.device) == cuda_device\n    _ = model(SOURCE)\n    assert str(model.device) == cuda_device\n\n    # Test CPU again\n    model = model.cpu()\n    assert str(model.device) == "cpu"\n    _ = model(SOURCE)\n    assert str(model.device) == "cpu"\n\n    # Test CUDA again\n    model = model.to(cuda_device)\n    assert str(model.device) == cuda_device\n    _ = model(SOURCE)\n    assert str(model.device) == cuda_device\n\n\n@pytest.mark.skipif(not DEVICES, reason="No CUDA devices available")\ndef test_autobatch():\n    """Check optimal batch size for YOLO model training using autobatch utility."""\n    from ultralytics.utils.autobatch import check_train_batch_size\n\n    check_train_batch_size(YOLO(MODEL).model.to(f"cuda:{DEVICES[0]}"), imgsz=128, amp=True)\n\n\n@pytest.mark.slow\n@pytest.mark.skipif(not DEVICES, reason="No CUDA devices available")\ndef test_utils_benchmarks():\n    """Profile YOLO models for performance benchmarks."""\n    from ultralytics.utils.benchmarks import ProfileModels\n\n    # Pre-export a dynamic engine model to use dynamic inference\n    YOLO(MODEL).export(format="engine", imgsz=32, dynamic=True, batch=1, device=DEVICES[0])\n    ProfileModels(\n        [MODEL],\n        imgsz=32,\n        half=False,\n        min_time=1,\n        num_timed_runs=3,\n        num_warmup_runs=1,\n        device=DEVICES[0],\n    ).run()\n\n\n@pytest.mark.skipif(not DEVICES, reason="No CUDA devices available")\ndef test_predict_sam():\n    """Test SAM model predictions using different prompts."""\n    from ultralytics import SAM\n    from ultralytics.models.sam import Predictor as SAMPredictor\n\n    model = SAM(WEIGHTS_DIR / "sam2.1_b.pt")\n    model.info()\n\n    # Run inference with various prompts\n    model(SOURCE, device=DEVICES[0])\n    model(SOURCE, bboxes=[439, 437, 524, 709], device=DEVICES[0])\n    model(ASSETS / "zidane.jpg", points=[900, 370], device=DEVICES[0])\n    model(ASSETS / "zidane.jpg", points=[900, 370], labels=[1], device=DEVICES[0])\n    model(ASSETS / "zidane.jpg", points=[[900, 370]], labels=[1], device=DEVICES[0])\n    model(ASSETS / "zidane.jpg", points=[[400, 370], [900, 370]], labels=[1, 1], device=DEVICES[0])\n    model(ASSETS / "zidane.jpg", points=[[[900, 370], [1000, 100]]], labels=[[1, 1]], device=DEVICES[0])\n\n    # Test predictor\n    predictor = SAMPredictor(\n        overrides=dict(\n            conf=0.25,\n            task="segment",\n            mode="predict",\n            imgsz=1024,\n            model=WEIGHTS_DIR / "mobile_sam.pt",\n            device=DEVICES[0],\n        )\n    )\n    predictor.set_image(ASSETS / "zidane.jpg")\n    # predictor(bboxes=[439, 437, 524, 709])\n    # predictor(points=[900, 370], labels=[1])\n    predictor.reset_image()\n',
            'ultralytics/utils/autobatch.py': '# Ultralytics 🚀 AGPL-3.0 License - https://ultralytics.com/license\n"""Functions for estimating the best YOLO batch size to use a fraction of the available CUDA memory in PyTorch."""\n\nfrom __future__ import annotations\n\nimport os\nfrom copy import deepcopy\n\nimport numpy as np\nimport torch\n\nfrom ultralytics.utils import DEFAULT_CFG, LOGGER, colorstr\nfrom ultralytics.utils.torch_utils import autocast, profile_ops\n\n\ndef check_train_batch_size(\n    model: torch.nn.Module,\n    imgsz: int = 640,\n    amp: bool = True,\n    batch: int | float = -1,\n    max_num_obj: int = 1,\n) -> int:\n    """Compute optimal YOLO training batch size using the autobatch() function.\n\n    Args:\n        model (torch.nn.Module): YOLO model to check batch size for.\n        imgsz (int, optional): Image size used for training.\n        amp (bool, optional): Use automatic mixed precision if True.\n        batch (int | float, optional): Fraction of GPU memory to use. If -1, use default.\n        max_num_obj (int, optional): The maximum number of objects from dataset.\n\n    Returns:\n        (int): Optimal batch size computed using the autobatch() function.\n\n    Notes:\n        If 0.0 < batch < 1.0, it\'s used as the fraction of GPU memory to use.\n        Otherwise, a default fraction of 0.6 is used.\n    """\n    with autocast(enabled=amp):\n        return autobatch(\n            deepcopy(model).train(), imgsz, fraction=batch if 0.0 < batch < 1.0 else 0.6, max_num_obj=max_num_obj\n        )\n\n\ndef autobatch(\n    model: torch.nn.Module,\n    imgsz: int = 640,\n    fraction: float = 0.60,\n    batch_size: int = DEFAULT_CFG.batch,\n    max_num_obj: int = 1,\n) -> int:\n    """Automatically estimate the best YOLO batch size to use a fraction of the available CUDA memory.\n\n    Args:\n        model (torch.nn.Module): YOLO model to compute batch size for.\n        imgsz (int, optional): The image size used as input for the YOLO model.\n        fraction (float, optional): The fraction of available CUDA memory to use.\n        batch_size (int, optional): The default batch size to use if an error is detected.\n        max_num_obj (int, optional): The maximum number of objects from dataset.\n\n    Returns:\n        (int): The optimal batch size.\n    """\n    # Check device\n    prefix = colorstr("AutoBatch: ")\n    LOGGER.info(f"{prefix}Computing optimal batch size for imgsz={imgsz} at {fraction * 100}% CUDA memory utilization.")\n    device = next(model.parameters()).device  # get model device\n    if device.type in {"cpu", "mps"}:\n        LOGGER.warning(f"{prefix}intended for CUDA devices, using default batch-size {batch_size}")\n        return batch_size\n    if torch.backends.cudnn.benchmark:\n        LOGGER.warning(f"{prefix}Requires torch.backends.cudnn.benchmark=False, using default batch-size {batch_size}")\n        return batch_size\n\n    # Inspect CUDA memory\n    gb = 1 << 30  # bytes to GiB (1024 ** 3)\n    d = f"CUDA:{os.getenv(\'CUDA_VISIBLE_DEVICES\', \'0\').strip()[0]}"  # \'CUDA:0\'\n    properties = torch.cuda.get_device_properties(device)  # device properties\n    t = properties.total_memory / gb  # GiB total\n    r = torch.cuda.memory_reserved(device) / gb  # GiB reserved\n    a = torch.cuda.memory_allocated(device) / gb  # GiB allocated\n    f = t - (r + a)  # GiB free\n    LOGGER.info(f"{prefix}{d} ({properties.name}) {t:.2f}G total, {r:.2f}G reserved, {a:.2f}G allocated, {f:.2f}G free")\n\n    # Profile batch sizes\n    batch_sizes = [1, 2, 4, 8, 16] if t < 16 else [1, 2, 4, 8, 16, 32, 64]\n    try:\n        img = [torch.empty(b, 3, imgsz, imgsz) for b in batch_sizes]\n        results = profile_ops(img, model, n=1, device=device, max_num_obj=max_num_obj)\n\n        # Fit a solution\n        xy = [\n            [x, y[2]]\n            for i, (x, y) in enumerate(zip(batch_sizes, results))\n            if y  # valid result\n            and isinstance(y[2], (int, float))  # is numeric\n            and 0 < y[2] < t  # between 0 and GPU limit\n            and (i == 0 or not results[i - 1] or y[2] > results[i - 1][2])  # first item or increasing memory\n        ]\n        fit_x, fit_y = zip(*xy) if xy else ([], [])\n        p = np.polyfit(fit_x, fit_y, deg=1)  # first-degree polynomial fit in log space\n        b = int((round(f * fraction) - p[1]) / p[0])  # y intercept (optimal batch size)\n        if None in results:  # some sizes failed\n            i = results.index(None)  # first fail index\n            if b >= batch_sizes[i]:  # y intercept above failure point\n                b = batch_sizes[max(i - 1, 0)]  # select prior safe point\n        if b < 1 or b > 1024:  # b outside of safe range\n            LOGGER.warning(f"{prefix}batch={b} outside safe range, using default batch-size {batch_size}.")\n            b = batch_size\n\n        fraction = (np.polyval(p, b) + r + a) / t  # predicted fraction\n        LOGGER.info(f"{prefix}Using batch-size {b} for {d} {t * fraction:.2f}G/{t:.2f}G ({fraction * 100:.0f}%) ✅")\n        return b\n    except Exception as e:\n        LOGGER.warning(f"{prefix}error detected: {e},  using default batch-size {batch_size}.")\n        return batch_size\n    finally:\n        torch.cuda.empty_cache()\n',
        }
